 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { Grid, GridItem, PageSection, Title } from '@patternfly/react-core';
 4	
 5	import PipelineVisualization from './PipelineVisualization';
 6	import { ResourceSummary } from '../details-page/details-page';
 7	import DynamicResourceLinkList from '../triggers-details/DynamicResourceLinkList';
 8	import { WorkspaceDefinitionList } from '../pipelines-tasks';
 9	import { PipelineModel, TriggerTemplateModel } from '../../models';
10	import { PipelineDetailsTabProps } from './types';
11	import { getPipelineTaskLinks } from './utils';
12	import TriggerTemplateResourceLink from './TriggerTemplateResourceLink';
13	import { usePipelineTriggerTemplateNames } from '../utils/triggers';
14	
15	const PipelineDetails: React.FC<PipelineDetailsTabProps> = ({
16	  obj: pipeline,
17	}) => {
18	  const { t } = useTranslation('plugin__pipelines-console-plugin');
19	  const templateNames =
20	    usePipelineTriggerTemplateNames(
21	      pipeline?.metadata?.name,
22	      pipeline?.metadata?.namespace,
23	    ) || [];
24	
25	  const { taskLinks, finallyTaskLinks } = getPipelineTaskLinks(pipeline);
26	
27	  return (
28	    <>
29	      <PageSection isFilled variant="light">
30	        <Title headingLevel="h2">{t('Pipeline details')}</Title>
31	        <PipelineVisualization pipeline={pipeline} />
32	        <Grid hasGutter>
33	          <GridItem sm={6}>
34	            <ResourceSummary resource={pipeline} model={PipelineModel} />
35	          </GridItem>
36	          <GridItem sm={6}>
37	            <TriggerTemplateResourceLink
38	              namespace={pipeline.metadata.namespace}
39	              model={TriggerTemplateModel}
40	              links={templateNames}
41	            />
42	            <DynamicResourceLinkList
43	              namespace={pipeline.metadata.namespace}
44	              links={taskLinks}
45	              title={t('Tasks')}
46	            />
47	            <DynamicResourceLinkList
48	              namespace={pipeline.metadata.namespace}
49	              links={finallyTaskLinks}
50	              title={t('Finally tasks')}
51	            />
52	            <WorkspaceDefinitionList obj={pipeline} />
53	          </GridItem>
54	        </Grid>
55	      </PageSection>
56	    </>
57	  );
58	};
59	
60	export default PipelineDetails;

